{
  "ip_rights": {
    "summary": "Perpetual, irrevocable, worldwide license for one-time $50K payment",
    "owner_of_deliverables": "Licensor retains ownership; Licensee gets perpetual license",
    "license_scope": "Perpetual, irrevocable, worldwide, can use/modify/distribute for any purpose",
    "concerns": [
      "Perpetual license for one-time payment creates revenue mismatch",
      "Irrevocable means cannot terminate even for breach",
      "Licensee can distribute (sublicense?) to unlimited parties",
      "No ongoing maintenance, support, or update obligations",
      "Licensee could compete with Licensor using the licensed software"
    ],
    "extracted_text": "Section 2.1: 'Licensor grants...perpetual, irrevocable, worldwide license to use, modify, and distribute...'"
  },
  "risk_assessment": {
    "overall_risk_level": "high",
    "risk_score": 85,
    "red_flags": [
      {
        "category": "IP",
        "severity": "critical",
        "issue": "Perpetual, irrevocable license for one-time payment with distribution rights",
        "detail": "This license structure creates significant business risk if we are the licensor. We receive $50K once but grant perpetual rights forever. Licensee can modify and distribute the software (potentially to competitors or creating their own competing product). 'Irrevocable' means we cannot terminate even if licensee breaches. This is essentially selling our software IP for $50K with no ongoing revenue or control. If we are the licensee, this is extremely favorable but licensor may later regret these terms.",
        "recommendation": "If we are LICENSOR: REJECT. NEGOTIATE: (1) Term-based license (e.g., 5-year term with renewal), OR (2) Restrict distribution/sublicensing rights, OR (3) Significantly higher license fee if perpetual, OR (4) Remove 'irrevocable' to allow termination for breach. If we are LICENSEE: Proceed but expect licensor pushback on these favorable terms.",
        "business_impact": "If licensor: Massive revenue loss, loss of control over IP, potential competitive threat. If licensee: Highly favorable terms that may not be sustainable long-term."
      }
    ]
  }
}

